    "Dateien verwalten" => "Manage files",
    "Dateien werden hochgeladen" => "File upload in progress",
    "Datei löschen" => "Remove file",
    "Dateiname" => "File name",
    "Datei wird hochgeladen" => "uploading file",
    "Datei übersetzen" => "Translate file",
    "Daten der Auswahlliste" => "Pick-list data",
    "Daten nicht verfügbar" => "Data unavailable",
    "Dauerhaft gesperrt" => "Blocked",
    "Deadline" => "Deadline",
    "Deadline Datum" => "Deadline date",
    "Deaktiviert" => "Disabled",
